## Set up React Navigation for Expo and React Native

### 1. Install core dependencies
- React Navigation is split into packages â€” install the core and the native helpers:
```bash
npx expo install @react-navigation/native react-native-screens react-native-safe-area-context
```
- IMPORTANT: Use `npx expo install` (NOT `npm install`) so Expo picks the compatible version for your SDK.
- `react-native-screens` provides native stack screens for better performance.
- `react-native-safe-area-context` handles the notch and home indicator on modern devices.

### 2. Choose and install a navigator
- Install the navigator types you need:
```bash
# Stack navigator (most common â€” push/pop screens)
npx expo install @react-navigation/native-stack

# Bottom tab bar
npx expo install @react-navigation/bottom-tabs

# Material top tabs (horizontal swipe)
npx expo install @react-navigation/material-top-tabs react-native-tab-view

# Drawer (side menu)
npx expo install @react-navigation/drawer react-native-gesture-handler react-native-reanimated
```
- For most apps, start with `native-stack` + `bottom-tabs`.

### 3. Wrap the app in NavigationContainer
- Wrap your root component in `<NavigationContainer>` in `App.tsx`:
```tsx
import { NavigationContainer } from '@react-navigation/native';

export default function App() {
  return (
    <NavigationContainer>
      <RootNavigator />
    </NavigationContainer>
  );
}
```
- There must be exactly ONE `<NavigationContainer>` at the root of your app.

### 4. Define TypeScript route params
- Declare param types for all screens to get full type safety:
```ts
// src/types/navigation.ts
export type RootStackParamList = {
  Home: undefined;
  Profile: { userId: string };
  Settings: undefined;
};

export type TabParamList = {
  Feed: undefined;
  Search: undefined;
  Profile: { userId: string };
};
```
- Then create typed hooks (do this once and reuse):
```ts
// src/types/navigation.ts (add to the same file)
import { NativeStackNavigationProp } from '@react-navigation/native-stack';
import { RouteProp } from '@react-navigation/native';

export type RootStackNavProp<T extends keyof RootStackParamList> =
  NativeStackNavigationProp<RootStackParamList, T>;

export type RootStackRouteProp<T extends keyof RootStackParamList> =
  RouteProp<RootStackParamList, T>;
```

### 5. Create a Stack navigator
```tsx
// src/navigation/RootNavigator.tsx
import { createNativeStackNavigator } from '@react-navigation/native-stack';
import { RootStackParamList } from '../types/navigation';
import HomeScreen from '../screens/HomeScreen';
import ProfileScreen from '../screens/ProfileScreen';

const Stack = createNativeStackNavigator<RootStackParamList>();

export function RootNavigator() {
  return (
    <Stack.Navigator
      initialRouteName="Home"
      screenOptions={{
        headerStyle: { backgroundColor: '#fff' },
        headerTintColor: '#000',
      }}
    >
      <Stack.Screen name="Home" component={HomeScreen} />
      <Stack.Screen
        name="Profile"
        component={ProfileScreen}
        options={{ title: 'User Profile' }}
      />
    </Stack.Navigator>
  );
}
```

### 6. Navigate between screens
- In a screen component, access the typed `navigation` and `route` props:
```tsx
// src/screens/HomeScreen.tsx
import { useNavigation } from '@react-navigation/native';
import { RootStackNavProp } from '../types/navigation';

export default function HomeScreen() {
  const navigation = useNavigation<RootStackNavProp<'Home'>>();

  return (
    <Button
      title="Go to Profile"
      onPress={() => navigation.navigate('Profile', { userId: '123' })}
    />
  );
}
```
- Access route params with `useRoute()`:
```tsx
// src/screens/ProfileScreen.tsx
import { useRoute } from '@react-navigation/native';
import { RootStackRouteProp } from '../types/navigation';

export default function ProfileScreen() {
  const route = useRoute<RootStackRouteProp<'Profile'>>();
  const { userId } = route.params; // fully typed
  return <Text>User ID: {userId}</Text>;
}
```

### 7. Add a Bottom Tab bar
```tsx
// src/navigation/TabNavigator.tsx
import { createBottomTabNavigator } from '@react-navigation/bottom-tabs';
import { Ionicons } from '@expo/vector-icons';
import { TabParamList } from '../types/navigation';
import FeedScreen from '../screens/FeedScreen';
import SearchScreen from '../screens/SearchScreen';

const Tab = createBottomTabNavigator<TabParamList>();

export function TabNavigator() {
  return (
    <Tab.Navigator
      screenOptions={({ route }) => ({
        tabBarIcon: ({ color, size }) => {
          const iconName = route.name === 'Feed' ? 'home' : 'search';
          return <Ionicons name={iconName} size={size} color={color} />;
        },
        tabBarActiveTintColor: '#6366f1',
        tabBarInactiveTintColor: 'gray',
      })}
    >
      <Tab.Screen name="Feed" component={FeedScreen} />
      <Tab.Screen name="Search" component={SearchScreen} />
    </Tab.Navigator>
  );
}
```
- To nest tabs inside a stack, use `TabNavigator` as the component for one of the stack screens.

### 8. Nest navigators (Stack inside Tabs â€” common pattern)
```tsx
// App structure: Tabs at root, each tab has its own Stack
export function RootNavigator() {
  return (
    <Stack.Navigator screenOptions={{ headerShown: false }}>
      <Stack.Screen name="Tabs" component={TabNavigator} />
      <Stack.Screen name="Settings" component={SettingsScreen} />
    </Stack.Navigator>
  );
}
```
- IMPORTANT: When nesting, set `headerShown: false` on the outer navigator's screen to avoid double headers.

### 9. Configure deep linking
- Add a `linking` config to `<NavigationContainer>` for universal links and custom schemes:
```tsx
const linking = {
  prefixes: ['myapp://', 'https://myapp.com'],
  config: {
    screens: {
      Home: '',
      Profile: 'user/:userId',
      Settings: 'settings',
    },
  },
};

<NavigationContainer linking={linking}>
  <RootNavigator />
</NavigationContainer>
```
- Then in `app.json` (Expo), add the scheme:
```json
{
  "expo": {
    "scheme": "myapp"
  }
}
```

### Common errors & fixes
- **`Error: couldn't find a navigation object`** â€” You called `useNavigation()` in a component that is not a child of `<NavigationContainer>`. Move the component into the navigator tree.
- **`The action NAVIGATE with payload was not handled`** â€” The target screen name doesn't exist in the navigator. Check for typos between the `Stack.Screen name` and `navigation.navigate('ScreenName')`.
- **Blank screen / no transition animation** â€” You likely forgot to install `react-native-screens` or didn't run `npx expo install`. Run `npx expo install react-native-screens` and restart the Metro bundler.
- **`requireNativeComponent: "RNCSafeAreaView" was not found`** â€” `react-native-safe-area-context` needs a native module rebuild. Run `npx expo prebuild` or ensure you're using an Expo dev client build.
- **Drawer swipe gesture not working** â€” For the drawer navigator, you must import and call `import 'react-native-gesture-handler'` at the very TOP of your `App.tsx` entry file, before any other imports.
- **TypeScript: `Argument of type 'string' is not assignable to parameter`** â€” Your param list types are mismatched. Ensure the `ParamList` type for `navigate()` matches the `createNativeStackNavigator<YourParamList>()` generic.
- **Back button doesn't dismiss modal** â€” Use `presentation: 'modal'` in the screen options and `navigation.goBack()` rather than `navigation.navigate()` to dismiss.

### What NOT to do
- Do NOT use `npm install` for React Navigation packages in an Expo project â€” use `npx expo install` to get SDK-compatible versions. Mismatched versions cause cryptic native errors.
- Do NOT put `<NavigationContainer>` inside a screen component â€” there must be exactly one at the root.
- Do NOT use `navigation.push()` and `navigation.navigate()` interchangeably â€” `navigate()` goes to an existing screen instance or creates one; `push()` always creates a new instance on the stack.
- Do NOT import `@react-navigation/drawer` without also installing `react-native-gesture-handler` and `react-native-reanimated` â€” the drawer requires native gesture support.
- Do NOT access `navigation` or `route` in components that aren't directly rendered by a `Stack.Screen` or `Tab.Screen` â€” use `useNavigation()` / `useRoute()` hooks for components deeper in the tree.
- Do NOT pass navigation props down through multiple component layers â€” use the `useNavigation()` hook at any level inside the navigator tree instead.
- Do NOT define new param list types inside component files â€” keep them in a shared `src/types/navigation.ts` file so all screens can import the same source of truth.
